{
  "ghost_echo_protocol": {
    "action": "Reverse-reverb on the first syllable/note of a theme",
    "pre_delay": "Synchronized to 1/2 or 1/4 note before the hit",
    "processing": "High-pass at 1kHz + Phaser (4-stage) + Grain-delay",
    "mixing": "Fade-in duration: 500ms. End point: Zero cross-fade with the dry signal",
    "goal": "Creating the sense of 'Sound pulling itself out of the Void'."
  }
}
